// Some portions generated by Codex
package org.eclipse.rdf4j.sail.lmdb;

import static org.assertj.core.api.Assertions.assertThat;

import java.io.File;
import java.util.List;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.Literal;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.model.vocabulary.XSD;
import org.eclipse.rdf4j.query.BindingSet;
import org.eclipse.rdf4j.query.QueryResults;
import org.eclipse.rdf4j.repository.sail.SailRepository;
import org.eclipse.rdf4j.repository.sail.SailRepositoryConnection;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

/**
 * Native-expression regression coverage. These tests require the LMDB native row/aggregate path to evaluate supported
 * scalar expressions from primitive value ids and decoded literal payloads, not by materializing RDF4J Value/Literal
 * wrappers through {@link NativeLmdbQuerySource#lazyValue(long)}.
 */
public class LmdbNativeExpressionFilterTest {

	private static final String EX = "http://example.com/";

	@TempDir
	File dataDir;

	private SailRepository repository;

	@BeforeEach
	public void setUp() {
		repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc,ospc")));
		try (SailRepositoryConnection conn = repository.getConnection()) {
			ValueFactory vf = conn.getValueFactory();
			IRI price = vf.createIRI(EX, "price");
			IRI label = vf.createIRI(EX, "label");

			IRI s0 = vf.createIRI(EX, "s0");
			IRI s1 = vf.createIRI(EX, "s1");
			IRI s2 = vf.createIRI(EX, "s2");

			conn.add(s0, price, vf.createLiteral(120));
			conn.add(s1, price, vf.createLiteral(121));
			conn.add(s2, price, vf.createLiteral("00121", XSD.INTEGER));

			conn.add(s0, label, vf.createLiteral("alpha"));
			conn.add(s1, label, vf.createLiteral("Alphabetical stored literal"));
			conn.add(s2, label, vf.createLiteral("beta"));
		}
	}

	@AfterEach
	public void tearDown() {
		repository.shutDown();
	}

	private long count(String query) {
		try (SailRepositoryConnection conn = repository.getConnection()) {
			List<BindingSet> rows = QueryResults.asList(conn.prepareTupleQuery(query).evaluate());
			assertThat(rows).hasSize(1);
			return ((Literal) rows.get(0).getValue("c")).longValue();
		}
	}

	private void resetNativeExpressionCounters() {
		LmdbNativeExpressionCompiler.COMPILED_FILTERS.set(0);
		LmdbNativeExpressionCompiler.LAZY_VALUE_CALLS.set(0);
	}

	@Test
	public void numericValueEqualityDoesNotMaterializeLiterals() {
		resetNativeExpressionCounters();

		long result = count("PREFIX ex: <" + EX + ">\n"
				+ "SELECT (COUNT(?s) AS ?c) WHERE {\n"
				+ "  ?s ex:price ?price .\n"
				+ "  FILTER(?price = 121)\n"
				+ "}");

		assertThat(result).isEqualTo(2);
		assertThat(LmdbNativeExpressionCompiler.COMPILED_FILTERS.get()).isGreaterThan(0);
		assertThat(LmdbNativeExpressionCompiler.LAZY_VALUE_CALLS.get()).isZero();
	}

	@Test
	public void stringFunctionFilterDoesNotMaterializeStoredLiterals() {
		resetNativeExpressionCounters();

		long result = count("PREFIX ex: <" + EX + ">\n"
				+ "SELECT (COUNT(?s) AS ?c) WHERE {\n"
				+ "  ?s ex:label ?label .\n"
				+ "  FILTER(CONTAINS(LCASE(STR(?label)), \"alpha\"))\n"
				+ "}");

		assertThat(result).isEqualTo(2);
		assertThat(LmdbNativeExpressionCompiler.COMPILED_FILTERS.get()).isGreaterThan(0);
		assertThat(LmdbNativeExpressionCompiler.LAZY_VALUE_CALLS.get()).isZero();
	}

	@Test
	public void negatedComparisonErrorDropsUnboundOptionalRows() {
		resetNativeExpressionCounters();

		long result = count("PREFIX ex: <" + EX + ">\n"
				+ "SELECT (COUNT(?s) AS ?c) WHERE {\n"
				+ "  ?s ex:price ?price .\n"
				+ "  OPTIONAL { ?s ex:missing ?missing }\n"
				+ "  FILTER(!(?missing = 1))\n"
				+ "}");

		assertThat(result).isZero();
		assertThat(LmdbNativeExpressionCompiler.COMPILED_FILTERS.get()).isGreaterThan(0);
		assertThat(LmdbNativeExpressionCompiler.LAZY_VALUE_CALLS.get()).isZero();
	}

	@Test
	public void constantSameTermFallsBackWhenTermIdIsUnavailable() {
		resetNativeExpressionCounters();

		long result = count("PREFIX ex: <" + EX + ">\n"
				+ "SELECT (COUNT(?s) AS ?c) WHERE {\n"
				+ "  ?s ex:price ?price .\n"
				+ "  FILTER(sameTerm(\"never stored\", \"never stored\"))\n"
				+ "}");

		assertThat(result).isEqualTo(3);
		assertThat(LmdbNativeExpressionCompiler.COMPILED_FILTERS.get()).isZero();
	}
}
